    namespace SecretAgent {
        // Signal signatures
        interface SignalSignatures extends GObject.Object.SignalSignatures {
            /**
             * Indicates the result of a registration request; if `error` is NULL the
             * request was successful.
             * @signal
             * @run-first
             */
            'registration-result': (arg0: any | null) => void;
            'notify::auto-register': (pspec: GObject.ParamSpec) => void;
            'notify::capabilities': (pspec: GObject.ParamSpec) => void;
            'notify::identifier': (pspec: GObject.ParamSpec) => void;
            'notify::registered': (pspec: GObject.ParamSpec) => void;
        }

        // Constructor properties interface

        interface ConstructorProps extends GObject.Object.ConstructorProps {
            auto_register: boolean;
            autoRegister: boolean;
            capabilities: SecretAgentCapabilities;
            identifier: string;
            registered: boolean;
        }
    }

    /**
     * @gir-type Class
     */
    abstract class SecretAgent extends GObject.Object {
        static $gtype: GObject.GType<SecretAgent>;

        // Properties

        /**
         * If TRUE, the agent will attempt to automatically register itself after
         * it is created (via an idle handler) and to re-register itself if
         * NetworkManager restarts.  If FALSE, the agent does not automatically
         * register with NetworkManager, and `nm_secret_agent_register()` must be
         * called.  If 'auto-register' is TRUE, calling `nm_secret_agent_unregister()`
         * will suppress auto-registration until `nm_secret_agent_register()` is
         * called, which re-enables auto-registration.
         */
        get auto_register(): boolean;
        set auto_register(val: boolean);
        /**
         * If TRUE, the agent will attempt to automatically register itself after
         * it is created (via an idle handler) and to re-register itself if
         * NetworkManager restarts.  If FALSE, the agent does not automatically
         * register with NetworkManager, and `nm_secret_agent_register()` must be
         * called.  If 'auto-register' is TRUE, calling `nm_secret_agent_unregister()`
         * will suppress auto-registration until `nm_secret_agent_register()` is
         * called, which re-enables auto-registration.
         */
        get autoRegister(): boolean;
        set autoRegister(val: boolean);
        /**
         * A bitfield of %NMSecretAgentCapabilities.
         */
        get capabilities(): SecretAgentCapabilities;
        set capabilities(val: SecretAgentCapabilities);
        /**
         * Identifies this agent; only one agent in each user session may use the
         * same identifier.  Identifier formatting follows the same rules as
         * D-Bus bus names with the exception that the ':' character is not
         * allowed.  The valid set of characters is "[A-Z][a-z][0-9]_-." and the
         * identifier is limited in length to 255 characters with a minimum
         * of 3 characters.  An example valid identifier is 'org.gnome.nm-applet'
         * (without quotes).
         * @construct-only
         */
        get identifier(): string;
        /**
         * `true` if the agent is registered with NetworkManager, `false` if not.
         * @read-only
         */
        get registered(): boolean;

        /**
         * Compile-time signal type information.
         *
         * This instance property is generated only for TypeScript type checking.
         * It is not defined at runtime and should not be accessed in JS code.
         * @internal
         */
        $signals: SecretAgent.SignalSignatures;

        // Constructors

        constructor(properties?: Partial<SecretAgent.ConstructorProps>, ...args: any[]);

        _init(...args: any[]): void;

        // Signals

        /** @signal */
        connect<K extends keyof SecretAgent.SignalSignatures>(
            signal: K,
            callback: GObject.SignalCallback<this, SecretAgent.SignalSignatures[K]>,
        ): number;
        connect(signal: string, callback: (...args: any[]) => any): number;
        /** @signal */
        connect_after<K extends keyof SecretAgent.SignalSignatures>(
            signal: K,
            callback: GObject.SignalCallback<this, SecretAgent.SignalSignatures[K]>,
        ): number;
        connect_after(signal: string, callback: (...args: any[]) => any): number;
        /** @signal */
        emit<K extends keyof SecretAgent.SignalSignatures>(
            signal: K,
            ...args: GObject.GjsParameters<SecretAgent.SignalSignatures[K]> extends [any, ...infer Q] ? Q : never
        ): void;
        emit(signal: string, ...args: any[]): void;

        // Virtual methods

        /**
         * @param connection_path
         * @param setting_name
         * @virtual
         */
        vfunc_cancel_get_secrets(connection_path: string, setting_name: string): void;
        /**
         * Asynchronously ask the agent to delete all saved secrets belonging to
         * `connection`.
         * @param connection a {@link NetworkManager.Connection}
         * @param connection_path
         * @param callback a callback, to be invoked when the operation is done
         * @virtual
         */
        vfunc_delete_secrets(
            connection: NetworkManager.Connection,
            connection_path: string,
            callback: SecretAgentDeleteSecretsFunc,
        ): void;
        /**
         * Asynchronously retrieve secrets belonging to `connection` for the
         * setting `setting_name`.  `flags` indicate specific behavior that the secret
         * agent should use when performing the request, for example returning only
         * existing secrets without user interaction, or requesting entirely new
         * secrets from the user.
         * @param connection the {@link NetworkManager.Connection} for which we're asked secrets
         * @param connection_path
         * @param setting_name the name of the secret setting
         * @param hints hints to the agent
         * @param flags flags that modify the behavior of the request
         * @param callback a callback, to be invoked when the operation is done
         * @virtual
         */
        vfunc_get_secrets(
            connection: NetworkManager.Connection,
            connection_path: string,
            setting_name: string,
            hints: string[],
            flags: SecretAgentGetSecretsFlags,
            callback: SecretAgentGetSecretsFunc,
        ): void;
        /**
         * @param error
         * @virtual
         */
        vfunc_registration_result(error: GLib.Error): void;
        /**
         * Asynchronously ensure that all secrets inside `connection`
         * are stored to disk.
         * @param connection a {@link NetworkManager.Connection}
         * @param connection_path
         * @param callback a callback, to be invoked when the operation is done
         * @virtual
         */
        vfunc_save_secrets(
            connection: NetworkManager.Connection,
            connection_path: string,
            callback: SecretAgentSaveSecretsFunc,
        ): void;

        // Methods

        /**
         * Asynchronously ask the agent to delete all saved secrets belonging to
         * `connection`.
         * @param connection a {@link NetworkManager.Connection}
         * @param callback a callback, to be invoked when the operation is done
         */
        delete_secrets(connection: NetworkManager.Connection, callback: SecretAgentDeleteSecretsFunc): void;
        /**
         * @returns a `true` if the agent is registered, `false` if it is not.
         */
        get_registered(): boolean;
        /**
         * Asynchronously retrieve secrets belonging to `connection` for the
         * setting `setting_name`.  `flags` indicate specific behavior that the secret
         * agent should use when performing the request, for example returning only
         * existing secrets without user interaction, or requesting entirely new
         * secrets from the user.
         * @param connection the {@link NetworkManager.Connection} for which we're asked secrets
         * @param setting_name the name of the secret setting
         * @param hints hints to the agent
         * @param flags flags that modify the behavior of the request
         * @param callback a callback, to be invoked when the operation is done
         */
        get_secrets(
            connection: NetworkManager.Connection,
            setting_name: string,
            hints: string[],
            flags: SecretAgentGetSecretsFlags | null,
            callback: SecretAgentGetSecretsFunc,
        ): void;
        /**
         * Registers the {@link NMClient.SecretAgent} with the NetworkManager secret manager,
         * indicating to NetworkManager that the agent is able to provide and save
         * secrets for connections on behalf of its user.  Registration is an
         * asynchronous operation and its success or failure is indicated via the
         * 'registration-result' signal.
         * @returns a new `true` if registration was successfully requested (this does not mean registration itself was successful), `false` if registration was not successfully requested.
         */
        register(): boolean;
        /**
         * Asynchronously ensure that all secrets inside `connection`
         * are stored to disk.
         * @param connection a {@link NetworkManager.Connection}
         * @param callback a callback, to be invoked when the operation is done
         */
        save_secrets(connection: NetworkManager.Connection, callback: SecretAgentSaveSecretsFunc): void;
        /**
         * Unregisters the {@link NMClient.SecretAgent} with the NetworkManager secret manager,
         * indicating to NetworkManager that the agent is will no longer provide or
         * store secrets on behalf of this user.
         * @returns a new `true` if unregistration was successful, `false` if it was not.
         */
        unregister(): boolean;
    }

